changeSet.sql:
ALTER TABLE social_history
  ADD CONSTRAINT ck_social_history_current_smoker_required
    CHECK (
      is_current_smoker IS NOT TRUE
        OR (smoke_start_date IS NOT NULL AND cigarette_amount IS NOT NULL)
      );

changeSet.rollback:
ٍ

        ALTER TABLE social_history
        DROP CONSTRAINT IF EXISTS ck_social_history_current_smoker_required;

changeSet.sql:
ALTER TABLE social_history
  ADD CONSTRAINT ck_social_history_previous_smoker_required
    CHECK (
      is_previous_smoker IS NOT TRUE
        OR smoke_quit_date IS NOT NULL
      );

ALTER TABLE social_history
  ADD CONSTRAINT ck_social_history_smoker_xor
    CHECK (
      NOT (is_current_smoker IS TRUE AND is_previous_smoker IS TRUE)
      );

ALTER TABLE social_history
  ADD CONSTRAINT ck_social_history_alcohol_since_when_required
    CHECK (
      alcohol_consumption IS NOT TRUE
        OR alcohol_since_when IS NOT NULL
      );
